#!/usr/bin/env bash
# Baseline verification for the coherence-to-internal_consistency rename.
# Generated by the initializer agent -- no dev server needed for this doc-only patch.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"

TARGET_FILES=(
  "plugins/harness/skills/harness/SKILL.md"
  "plugins/harness/skills/harness/references/patterns.md"
  "plugins/harness/agents/generator.md"
  "plugins/harness/skills/harness/roles/generator.md"
  "plugins/harness/agents/evaluator.md"
  "plugins/harness/skills/harness/roles/evaluator.md"
)

echo "Verifying target files exist..."
MISSING=0
for f in "${TARGET_FILES[@]}"; do
  if [ ! -f "$PROJECT_ROOT/$f" ]; then
    echo "MISSING: $f"
    MISSING=$((MISSING + 1))
  else
    echo "OK   -- $f"
  fi
done

echo ""

if [ "$MISSING" -gt 0 ]; then
  echo "FAIL -- $MISSING target file(s) missing"
  exit 1
fi

echo "All 6 target files exist."
echo ""
echo "Checking for 'coherence' in authenticity gate contexts..."

HITS=0
for f in "${TARGET_FILES[@]}"; do
  if grep -q "coherence" "$PROJECT_ROOT/$f" 2>/dev/null; then
    HITS=$((HITS + 1))
  fi
done

echo "Files containing 'coherence': $HITS/6"
echo ""

if [ "$HITS" -eq 6 ]; then
  echo "BASELINE CONFIRMED -- all files still contain 'coherence' (pre-rename state)"
elif [ "$HITS" -eq 0 ]; then
  echo "RENAME COMPLETE -- no files contain 'coherence' in dimension-name contexts"
else
  echo "PARTIAL -- $HITS/6 files still contain 'coherence'"
fi
